import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as t,c as a,e as r}from"./app-e1663f36.js";const i={},c=r('<h2 id="问题现象" tabindex="-1"><a class="header-anchor" href="#问题现象" aria-hidden="true">#</a> 问题现象</h2><p>点击fetch时，IDEA弹出如下错误：</p><p>unable to read askpass response from &#39;C: \\Users\\WUHU\\AppData\\Local\\JetBrains\\IntelliJIdea2023.2\\tmp\\intellij-git-askpass-local.sh&#39; bash: line 1: /dev/tty: No such device or address failed to execute prompt script (exit code 1) could not read Username for &#39;http://10.50.20.88&#39;: No such file or directory</p><h2 id="原因分析" tabindex="-1"><a class="header-anchor" href="#原因分析" aria-hidden="true">#</a> 原因分析</h2><p>原因是IDEA的git插件在使用git fetch时，会在本地生成一个临时文件，这个文件会在git fetch结束后被删除。</p><p>这个临时文件是用来获取git的用户名和密码的，如果这个文件被删除了，就会导致IDEA无法获取用户名和密码，从而导致fetch失败。</p><p>为什么该临时文件会被删除还不清除</p><h2 id="解决方案" tabindex="-1"><a class="header-anchor" href="#解决方案" aria-hidden="true">#</a> 解决方案</h2><p>在IDEA的设置中找到Git选项，然后找到<code>Use credential helper</code>，将其勾选即可</p><p>我猜测该配置的作用应该是从Git 内置的凭据助手中获取认证信息</p>',10),d=[c];function s(o,h){return t(),a("div",null,d)}const l=e(i,[["render",s],["__file","idea-fetch-failed.html.vue"]]);export{l as default};
